def parse_subject(subject: str) -> dict[str, Any]:
    """Parse a subject string into a dictionary."""
    result = {}
    parts = subject.split(",")
    for part in parts:
        key, value = part.split("=", 1)
        value = value.strip().strip('"')
        if key.strip() in ("level",):
            value = int(value)
        result[key.strip()] = value
    return result


def parse_resource(resource: str) -> dict[str, Any]:
    """Parse a resource string into a dictionary."""
    result = {}
    parts = resource.split(",")
    for part in parts:
        key, value = part.split("=", 1)
        value = value.strip().strip('"')
        result[key.strip()] = value
    return result


def parse_policy(policy: str) -> dict[str, Any]:
    """Parse a policy string into a dictionary with 'condition' and 'effect' keys."""
    condition, effect = policy.split("->")
    return {"condition": condition.strip(), "effect": effect.strip()}


def _eval_condition_node(node, context):
    if isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            return all(_eval_condition_node(v, context) for v in node.values)
        elif isinstance(node.op, ast.Or):
            return any(_eval_condition_node(v, context) for v in node.values)
    elif isinstance(node, ast.Compare):
        left = _eval_condition_node(node.left, context)
        for op, comparator in zip(node.ops, node.comparators):
            right = _eval_condition_node(comparator, context)
            if isinstance(op, ast.Eq):
                if not (left == right):
                    return False
            elif isinstance(op, ast.NotEq):
                if not (left != right):
                    return False
            elif isinstance(op, ast.Gt):
                if not (left > right):
                    return False
            elif isinstance(op, ast.GtE):
                if not (left >= right):
                    return False
            elif isinstance(op, ast.Lt):
                if not (left < right):
                    return False
            elif isinstance(op, ast.LtE):
                if not (left <= right):
                    return False
            left = right
        return True
    elif isinstance(node, ast.Name):
        return context[node.id]
    elif isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Not):
        return not _eval_condition_node(node.operand, context)
    elif isinstance(node, ast.Attribute):
        value = _eval_condition_node(node.value, context)
        return getattr(value, node.attr)
    else:
        raise ValueError(f"Unsupported expression: {ast.dump(node)}")


def evaluate_condition(condition: str, context: dict[str, Any]) -> bool:
    try:
        tree = ast.parse(condition, mode="eval")
    except SyntaxError as exc:
        raise ValueError(f"Invalid condition syntax: {condition!r}") from exc
    result = _eval_condition_node(tree.body, context)
    return bool(result)


def _extract_roles_from_condition(condition: str) -> set[str]:
    """Extract all role values referenced in a condition."""
    roles = set()
    try:
        tree = ast.parse(condition, mode="eval")
    except SyntaxError:
        return roles

    for node in ast.walk(tree):
        if isinstance(node, ast.Compare):
            if (isinstance(node.left, ast.Name) and node.left.id == "role"
                    and len(node.ops) == 1 and isinstance(node.ops[0], ast.Eq)
                    and isinstance(node.comparators[0], ast.Constant)
                    and isinstance(node.comparators[0].value, str)):
                roles.add(node.comparators[0].value)
    return roles


def solve(policies: list[str]) -> bool:
    allow_roles = set()
    deny_roles = set()

    for policy_str in policies:
        policy = parse_policy(policy_str)
        roles = _extract_roles_from_condition(policy["condition"])
        if policy["effect"] == "allow":
            allow_roles |= roles
        elif policy["effect"] == "deny":
            deny_roles |= roles

    return bool(allow_roles & deny_roles)
