import math
import re
from typing import Any

def nimbla_value(token: str) -> float:
    """Convert a Nimbla token to a numeric value."""
    if not _TOKEN_PATTERN.match(token):
        raise ValueError(f"Invalid Nimbla token: {token!r}")
    letter_index = ord(token[0]) - ord("A") + 1
    digit = int(token[1])
    return letter_index + digit / 10.0


def summarize_nimbla(series: dict[str, Any]) -> dict[str, Any]:
    """Return a statistical summary of a Nimbla series."""
    values = series["values"]
    if not values:
        return {
            "count": 0,
            "min": 0.0,
            "max": 0.0,
            "mean": 0.0,
            "std": 0.0,
        }
    mean = sum(values) / len(values)
    std = math.sqrt(sum((v - mean) ** 2 for v in values) / len(values))
    return {
        "count": len(values),
        "min": min(values),
        "max": max(values),
        "mean": mean,
        "std": std,
    }


def solve(series: str) -> float:
    """Parse the series and return the standard deviation from its statistical summary."""
    # Parse the series string: "NIM|ts1:token1,ts2:token2,..."
    if not series.startswith("NIM|"):
        raise ValueError(f"Invalid series format: {series!r}")

    body = series[4:]
    if not body:
        values = []
    else:
        entries = body.split(",")
        values = []
        for entry in entries:
            ts_token = entry.split(":")
            if len(ts_token) != 2:
                raise ValueError(f"Invalid entry: {entry!r}")
            token = ts_token[1]
            values.append(nimbla_value(token))

    series_dict = {"values": values}
    summary = summarize_nimbla(series_dict)
    return summary["std"]
